-- ============================================================
-- Audit Management System â€” Database Schema
-- Compatible with MySQL 8.x (H2 is auto-generated by JPA)
-- ============================================================

CREATE DATABASE IF NOT EXISTS auditdb CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE auditdb;

-- ===== USERS =====
CREATE TABLE users (
    id          BIGINT AUTO_INCREMENT PRIMARY KEY,
    username    VARCHAR(50)  NOT NULL UNIQUE,
    email       VARCHAR(100) NOT NULL UNIQUE,
    password    VARCHAR(255) NOT NULL,
    role        ENUM('ADMIN','AUDITOR','CLIENT') NOT NULL DEFAULT 'CLIENT',
    created_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- ===== AUDIT RECORDS =====
CREATE TABLE audit_records (
    id                  BIGINT AUTO_INCREMENT PRIMARY KEY,
    user_id             BIGINT NOT NULL,
    company_name        VARCHAR(200) NOT NULL,
    audit_type          ENUM('FINANCIAL','SECURITY','COMPLIANCE') NOT NULL,
    number_of_employees INT,
    has_firewall        BOOLEAN DEFAULT FALSE,
    has_antivirus       BOOLEAN DEFAULT FALSE,
    has_encryption      BOOLEAN DEFAULT FALSE,
    has_mfa             BOOLEAN DEFAULT FALSE,
    previous_incidents  BOOLEAN DEFAULT FALSE,
    compliance_level    ENUM('LOW','MEDIUM','HIGH') NOT NULL,
    data_sensitivity    ENUM('LOW','MEDIUM','HIGH','CRITICAL') NOT NULL,
    update_frequency    ENUM('RARELY','MONTHLY','WEEKLY','DAILY') NOT NULL,
    risk_score          INT,
    risk_level          ENUM('LOW','MEDIUM','HIGH','CRITICAL'),
    recommendations     TEXT,
    submitted_at        DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    INDEX idx_risk_level (risk_level),
    INDEX idx_user_id (user_id),
    INDEX idx_submitted_at (submitted_at)
);

